import { useState } from 'react';

export default function Reservation() {
  const [nom, setNom] = useState('');
  const [date, setDate] = useState('');
  const [heure, setHeure] = useState('');
  const [salle, setSalle] = useState('');
  const [message, setMessage] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!nom || !date || !heure || !salle) {
      setMessage("Veuillez remplir tous les champs.");
      return;
    }
    setMessage(`Réservation confirmée pour ${nom} le ${date} à ${heure} dans la salle ${salle}`);
    // ici on pourrait envoyer les données à l'API
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center p-4">
      <div className="bg-white shadow-lg rounded p-6 w-full max-w-lg">
        <h2 className="text-2xl font-bold mb-4 text-center text-purple-700">Réserver une salle</h2>
        {message && <p className="text-green-600 mb-4 text-center">{message}</p>}
        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            type="text"
            placeholder="Votre nom"
            value={nom}
            onChange={(e) => setNom(e.target.value)}
            className="w-full p-2 border rounded"
          />
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full p-2 border rounded"
          />
          <input
            type="time"
            value={heure}
            onChange={(e) => setHeure(e.target.value)}
            className="w-full p-2 border rounded"
          />
          <select
            value={salle}
            onChange={(e) => setSalle(e.target.value)}
            className="w-full p-2 border rounded"
          >
            <option value="">Choisissez une salle</option>
            <option value="A">Salle A</option>
            <option value="B">Salle B</option>
            <option value="C">Salle C</option>
          </select>
          <button type="submit" className="w-full bg-purple-600 text-white py-2 rounded hover:bg-purple-700 transition">
            Réserver
          </button>
        </form>
      </div>
    </div>
  );
}
